const SMS_LIMIT = 155; //160

// Przetwarzanie każdego elementu w danych
for (const item of items) {
  const input = item.json;

  // 1. Definiowanie pól
  const name = $('Webhook1').first().json.body.createdBy || '';


  // 2. Łączenie pól w format: "Imię Nazwisko; Tytuł; " (Z POLSKIMI ZNAKAMI)
  // Używamy separatorów "; " (dwa znaki)
  const firstPartRaw = `Knowshare: ${name}; `;

  // 3. Obliczenie DŁUGOŚCI tej części (na podstawie RAW stringu)
  const firstPartLength = firstPartRaw.length;

  // 4. Wyznaczenie różnicy (maksymalnego limitu dla Treści)
  const maxContentLength = SMS_LIMIT - firstPartLength;

  // Zapewnienie, że limit nie jest ujemny
  const finalContentLimit = Math.max(0, maxContentLength);

  // Dodanie nowych zmiennych do obiektu JSON:
  // - sms_firstPart: sformatowana część z polskimi znakami
  // - sms_contentLimit: obliczony limit znaków dla treści (dla Chat GPT)
  input.sms_firstPart = firstPartRaw;
  input.sms_contentLimit = finalContentLimit;
}

return items;

const attachments = $('Webhook1').first().json.body.attachments

const result = attachments
  .flat(Infinity)
  .filter(item => item && item.id)
  .map(item => ({ id: item.id }));

return [
  {
    json: {
      attachments: result
    }
  }
];

// 1. Pobierz surowy tekst JSON z OpenAI
let raw = $input.first().json.output?.[0]?.content?.[0]?.text || "";

// 2. Pobranie oryginalnej wiadomości (dla pola task_description)
const originalMessage = $('Safe subject and message').first()?.json?.safe_message || "";

// 3. Usuń potencjalne znaczniki kodu ```json ... ```
if (raw.includes("```")) {
    raw = raw.replace(/```json|```/g, "").trim();
}

// 4. Usuń nadmiarowe białe znaki
raw = raw.replace(/[\n\r\t\u00A0\uFEFF]/g, " ").trim();

let parsed;

// 5. Parsowanie JSON z obsługą błędów
try {
    parsed = JSON.parse(raw);
} catch (error) {
    return [{
        json: {
            task_title: "",
            interpretation: "",
            recommendation: "",
            task_description: "",
            priority: "",
            _error: "Błąd parsowania JSON: " + error.message + " | Czysty ciąg: " + raw.substring(0, 100) + "..."
        }
    }];
}

// 6. Transformacja do oczekiwanego formatu
const obj = (Array.isArray(parsed) && parsed.length > 0) ? parsed[0] : parsed;
const taskDescriptionData = obj.task_description || {};

// 7. Pobieranie wartości generowanych przez AI
const interpretation = taskDescriptionData.interpretation || "";
const recommendation = taskDescriptionData.recommendation || "";
const taskTitle = obj.task_title || "";

// 8. Mapowanie typu z Webhook na priority
const typeRaw = $('Webhook1').first()?.json?.body?.type;

const priorityMap = {
    "03_low": "03_low",
    "02_medium": "02_medium",
    "01_high": "01_high",
    "04_unknown": "04_unknown"
};

const priority = priorityMap[typeRaw] ?? "03_low"; // fallback domyślny

// 9. Tworzenie nowego pola 'task_description'
const newTaskDescription = `1: ${originalMessage} | 2: ${interpretation} | 3: ${recommendation}`;

// 10. Zwrócenie finalnego formatu
return [{
    json: {
        task_title: taskTitle,
        interpretation: interpretation,
        recommendation: recommendation,
        task_description: newTaskDescription,
        priority: priority
    }
}];

