// Pobierz dane wejściowe z Webhook
const subject = $input.first().json.body.subject || "";
const message = $input.first().json.body.message || "";

// Funkcja do oczyszczania tekstu
function sanitizeTextSafe(text) {
    if (!text) return "";

    // 1. Usuń wszystkie znaki kontrolne ASCII (0-31 i 127)
    text = text.replace(/[\x00-\x1F\x7F]/g, "");

    // 2. Usuń potencjalnie niebezpieczne znaki w JSON lub kodzie
    text = text.replace(/[`\\<>${}[\]]/g, "");

    // 3. Usuń wszystkie cudzysłowy i apostrofy (proste + typograficzne)
    text = text.replace(/["'‘’“”„‚«»]/g, "");

    // 4. Usuń nadmiarowe białe znaki (nowa linia, tab, niełamiąca spacja)
    text = text.replace(/[\n\r\t\u00A0\uFEFF]/g, " ").trim();

    // 5. Zamień wielokrotne spacje na pojedynczą
    text = text.replace(/\s{2,}/g, " ");

    return text;
}

// Oczyszczone pola
const safeSubject = sanitizeTextSafe(subject);
const safeMessage = sanitizeTextSafe(message);

// Zwrot danych do workflow
return [{
    json: {
        safe_subject: safeSubject,
        safe_message: safeMessage
    }
}];

for (const item of items) {
  if (!item.binary?.audio) continue;

  const file = item.binary.audio;
  if (!file.fileName) continue;

  const name = file.fileName.toLowerCase();

  if (name.endsWith('.mp3')) file.mimeType = 'audio/mpeg';
  else if (name.endsWith('.wav')) file.mimeType = 'audio/wav';
  else if (name.endsWith('.m4a')) file.mimeType = 'audio/mp4';
  else if (name.endsWith('.flac')) file.mimeType = 'audio/flac';
  else if (name.endsWith('.ogg') || name.endsWith('.oga')) file.mimeType = 'audio/ogg';
  else if (name.endsWith('.webm')) file.mimeType = 'audio/webm';
  else if (name.endsWith('.mp4')) file.mimeType = 'audio/mp4';
  else if (name.endsWith('.mpeg') || name.endsWith('.mpga')) file.mimeType = 'audio/mpeg';
  else if (name.endsWith('.aac')) file.mimeType = 'audio/aac';
  else file.mimeType = 'application/octet-stream'; // fallback

}

return items;

const allErrors = [];

const nodes = [
    'Create Picture Summary - error handling',
    'Audio analyze - error handling',
    'Create summary - error handling',
    'Text shortening - error handling',
    'Twilio - error handling'
];

for (const nodeName of nodes) {
    try {
        // Pobranie itemu w poprawny sposób
        const nodeItem = $node[nodeName]?.json;

        if (!nodeItem) continue;

        const nodeError = nodeItem.errorOpenAI1;

        if (
            typeof nodeError === 'string' &&
            nodeError.trim().length > 0
        ) {
            allErrors.push(nodeError);
        }

    } catch (err) {
        continue;
    }
}

return [{
    json: {
        sendEmail: allErrors.length > 0,
        body: allErrors.join("\n\n")
    }
}];

const input = $('Webhook1').first().json.body.attachments;

// spłaszczenie [[...]] → [...]
const flat = Array.isArray(input?.[0]) ? input[0] : input || [];

const IMAGE_EXT = ['png', 'jpg', 'jpeg', 'gif', 'webp'];

// filtr tylko obrazów po URL
const images = flat.filter(item => {
  const url = item?.url;
  if (!url || typeof url !== 'string') return false;

  const cleanUrl = url.split('?')[0];
  const ext = cleanUrl.split('.').pop()?.toLowerCase();

  return IMAGE_EXT.includes(ext);
});

// mapowanie do formatu [{id: ...}]
const mainImage = images.map(img => ({ id: img.id }));

return {
  mainImage
};

